import jakarta.ws.rs.ext.Provider;
import java.net.URI;
import java.util.Locale;

@Provider
@PreMatching
public class S3VirtualHostFilter implements ContainerRequestFilter {

    @Override
    public void filter(ContainerRequestContext requestContext) {
        String bucket = bucketFromHost(requestContext.getHeaderString("Host"));
        if (bucket == null) {
            return;
        }

        URI uri = requestContext.getUriInfo().getRequestUri();
        String path = uri.getRawPath();
        if (path == null || path.isEmpty() || "/".equals(path)) {
            path = "";
        } else if (!path.startsWith("/")) {
            path = "/" + path;
        }

        URI newUri = UriBuilder.fromUri(uri)
                .replacePath("/" + bucket + path)
                .build();

        requestContext.setRequestUri(newUri);
    }

    private String bucketFromHost(String hostHeader) {
        if (hostHeader == null || hostHeader.isBlank()) {
            return null;
        }

        String host = stripPort(hostHeader.strip());
        if (host.endsWith(".")) {
            host = host.substring(0, host.length() - 1);
        }

        String lowerHost = host.toLowerCase(Locale.ROOT);
        String bucket = bucketBefore(host, lowerHost, ".s3.");
        if (bucket == null) {
            bucket = bucketBefore(host, lowerHost, ".s3-");
        }
        if (bucket == null) {
            bucket = bucketBefore(host, lowerHost, ".localhost");
        }

        if (bucket == null || bucket.isBlank()
                || bucket.equalsIgnoreCase("s3") || bucket.equalsIgnoreCase("localhost")) {
            return null;
        }
        return bucket;
    }

    private String bucketBefore(String host, String lowerHost, String marker) {
        int markerIndex = lowerHost.indexOf(marker);
        return markerIndex > 0 ? host.substring(0, markerIndex) : null;
    }

    private String stripPort(String host) {
        if (host.startsWith("[")) {
            int bracket = host.indexOf(']');
            return bracket >= 0 ? host.substring(0, bracket + 1) : host;
        }
        int colon = host.lastIndexOf(':');
        return colon > 0 && host.indexOf(':') == colon ? host.substring(0, colon) : host;
    }
}

